// ✅ UPDATED: src/pages/OfficialControlScreen.js
// Fixes:
// 1) ":" stays on SAME LINE (no wrap under label)
// 2) NO hardcoded UI text in this screen — ALL titles/labels come from i18n (index.js)
//    (Only the actual values like plate/model/name stay as data)

import React, { useMemo } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Pressable,
  ScrollView,
} from "react-native";
import { useNavigation } from "@react-navigation/native";
import { useTranslation } from "../i18n";

export default function OfficialControlScreen() {
  const navigation = useNavigation();
  const { t } = useTranslation();

  // ✅ Dummy values only (not UI text)
  const data = useMemo(
    () => ({
      registration: {
        plate: "CE 458-Y",
        model: "Toyota Yaris (Sedan)",
        owner: "NGOUMOU Jean-Pierre",
      },
      licence: {
        number: "CUY-2026-TX-8842",
        validity: "01/01/2026 au 31/12/2026",
        zone: "Yaoundé Urbain",
        doorNumber: "1055-B",
      },
      driver: {
        initials: "FM",
        fullName: "FOUDA MEKONGO Christian",
        permit: "04/1055/B/2018",
        category: "B",
        cni: "112455987",
      },
      insurance: {
        company: "ACTIVA Assurance",
        expiry: "15/06/2026",
        status: "VALIDE",
      },
    }),
    []
  );

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView contentContainerStyle={styles.scroll} showsVerticalScrollIndicator={false}>
        {/* ===== Top row (Back) ===== */}
        <View style={styles.topRow}>
          <Pressable style={styles.backBtn} onPress={() => navigation.goBack()}>
            <Text style={styles.backIcon}>‹</Text>
            <Text style={styles.backText}>{t("common.back")}</Text>
          </Pressable>
        </View>

        {/* ===== Status banner ===== */}
        <View style={styles.bannerWrap}>
          <View style={styles.banner}>
            <View style={styles.bannerDot} />
            <Text style={styles.bannerText}>{t("official.statusAuthorized")}</Text>
          </View>
        </View>

        {/* ===== Cards ===== */}
        <SectionCard
          icon="🚕"
          title={t("official.vehicle.title")}
          subtitle={`(${t("official.vehicle.subtitle")})`}
          rows={[
            {
              icon: "🚗",
              label: t("official.vehicle.plate"),
              value: data.registration.plate,
            },
            {
              icon: "🚕",
              label: t("official.vehicle.model"),
              value: data.registration.model,
            },
            {
              icon: "📍",
              label: t("official.vehicle.owner"),
              value: data.registration.owner,
            },
          ]}
        />

        <SectionCard
          icon="✅"
          title={t("official.licence.title")}
          subtitle={`(${t("official.licence.subtitle")})`}
          rows={[
            {
              icon: "🚗",
              label: t("official.licence.number"),
              value: data.licence.number,
            },
            {
              icon: "🕒",
              label: t("official.licence.validity"),
              value: data.licence.validity,
            },
            {
              icon: "📍",
              label: t("official.licence.zone"),
              value: data.licence.zone,
            },
            {
              icon: "🚕",
              label: t("official.licence.doorNumber"),
              value: data.licence.doorNumber,
            },
          ]}
          headerVariant="green"
        />

        <SectionCard
          icon="🧑🏾‍✈️"
          title={t("official.driver.title")}
          subtitle={`(${t("official.driver.subtitle")})`}
          rows={[
            {
              icon: "🚗",
              label: t("official.driver.permit"),
              value: data.driver.permit,
            },
            {
              icon: "🅱️",
              label: t("official.driver.category"),
              value: data.driver.category,
            },
            {
              icon: "🪪",
              label: t("official.driver.cni"),
              value: data.driver.cni,
            },
          ]}
          headerVariant="green"
          topLeftAvatar={{ initials: data.driver.initials, name: data.driver.fullName }}
        />

        <SectionCard
          icon="✅"
          title={t("official.insurance.title")}
          subtitle={`(${t("official.insurance.subtitle")})`}
          rows={[
            {
              icon: "🚗",
              label: t("official.insurance.company"),
              value: data.insurance.company,
            },
            {
              icon: "🕒",
              label: t("official.insurance.expiry"),
              value: data.insurance.expiry,
            },
            {
              icon: "✅",
              label: t("official.insurance.status"),
              value: data.insurance.status,
              isStatus: true,
            },
          ]}
          headerVariant="green"
        />
      </ScrollView>
    </SafeAreaView>
  );
}

/* =========================
   Reusable Section Card
========================= */
function SectionCard({ icon, title, subtitle, rows, headerVariant = "green", topLeftAvatar }) {
  return (
    <View style={styles.card}>
      {/* Header */}
      <View style={[styles.sectionHeader, headerVariant === "green" && styles.sectionHeaderGreen]}>
        <Text style={styles.sectionHeaderIcon}>{icon}</Text>
        <View style={{ flex: 1 }}>
          <Text style={styles.sectionHeaderTitle}>
            {title} <Text style={styles.sectionHeaderSub}>{subtitle}</Text>
          </Text>
        </View>
      </View>

      {/* Optional avatar row (no real image) */}
      {topLeftAvatar ? (
        <View style={styles.avatarRow}>
          <View style={styles.avatarCircle}>
            <Text style={styles.avatarText}>{topLeftAvatar.initials}</Text>
          </View>
          <Text style={styles.avatarName}>{topLeftAvatar.name}</Text>
        </View>
      ) : null}

      {/* Rows */}
      {rows.map((r, idx) => (
        <View
          key={`${r.label}-${idx}`}
          style={[styles.row, idx === rows.length - 1 ? styles.rowLast : null]}
        >
          <Text style={styles.rowIcon}>{r.icon}</Text>

          {/* ✅ FIX: label + ":" are one single Text block (won't split into a new line) */}
          <Text style={styles.rowLabel} numberOfLines={1}>
            {r.label} :
          </Text>

          {r.isStatus ? (
            <View style={styles.statusChip}>
              <Text style={styles.statusChipText}>{r.value}</Text>
            </View>
          ) : (
            <Text style={styles.rowValue}>{r.value}</Text>
          )}
        </View>
      ))}
    </View>
  );
}

/* =========================
   Styles
========================= */

const GREEN = "#2F7D3A";
const DARK_GREEN = "#0F3C2F";
const HEADER_GREEN = "#DCEEDD";
const TEXT_DARK = "#0B1F14";
const MUTED_GREEN = "#4B6B57";
const CARD_BG = "#FFFFFF";
const PAGE_BG = "#EEF5F4";

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: PAGE_BG },

  scroll: {
    paddingHorizontal: 18,
    paddingTop: 16,
    paddingBottom: 28,
  },

  /* Top */
  topRow: {
    width: "100%",
    flexDirection: "row",
    justifyContent: "flex-start",
    marginBottom: 12,
  },
  backBtn: {
    backgroundColor: DARK_GREEN,
    borderRadius: 26,
    paddingVertical: 10,
    paddingHorizontal: 16,
    flexDirection: "row",
    alignItems: "center",
    gap: 10,
    shadowColor: "#000",
    shadowOpacity: 0.16,
    shadowRadius: 12,
    shadowOffset: { width: 0, height: 8 },
    elevation: 6,
  },
  backIcon: { color: "#fff", fontSize: 20, fontWeight: "900", marginTop: -1 },
  backText: { color: "#fff", fontSize: 18, fontWeight: "900" },

  /* Banner */
  bannerWrap: { width: "100%", alignItems: "center" },
  banner: {
    width: "92%",
    backgroundColor: HEADER_GREEN,
    borderRadius: 22,
    paddingVertical: 10,
    paddingHorizontal: 16,
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "center",
    gap: 12,
    borderWidth: 1,
    borderColor: "rgba(47,125,58,0.25)",
  },
  bannerDot: { width: 12, height: 12, borderRadius: 6, backgroundColor: GREEN },
  bannerText: { fontSize: 18, fontWeight: "900", letterSpacing: 1, color: "#1F6F3D" },

  /* Card */
  card: {
    marginTop: 16,
    borderRadius: 22,
    backgroundColor: CARD_BG,
    overflow: "hidden",
    shadowColor: "#000",
    shadowOpacity: 0.06,
    shadowRadius: 18,
    shadowOffset: { width: 0, height: 14 },
    elevation: 3,
  },

  /* Header */
  sectionHeader: {
    backgroundColor: "#E6EFE9",
    paddingVertical: 10,
    paddingHorizontal: 14,
    flexDirection: "row",
    alignItems: "center",
    gap: 10,
  },
  sectionHeaderGreen: { backgroundColor: HEADER_GREEN },
